import{_ as n,c as s,a as e,o as t}from"./app-CwFsTuGQ.js";const c={};function o(l,a){return t(),s("div",null,a[0]||(a[0]=[e(`<h1 id="local-cache" tabindex="-1"><a class="header-anchor" href="#local-cache"><span>Local Cache</span></a></h1><p>In this section, you will learn how to use the local cache to store data in the application&#39;s memory.</p><p>First, we need to configure the data pools and engine. In this example, we will create two pools: <code>default</code>, without any limit, and <code>test</code>, which can hold up to 100 elements:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">import</span> fluxaorm <span class="token string">&quot;github.com/latolukasz/fluxaorm/v2&quot;</span></span>
<span class="line"></span>
<span class="line">registry <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRegistry</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">registry<span class="token punctuation">.</span><span class="token function">RegisterLocalCache</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span></span>
<span class="line">registry<span class="token punctuation">.</span><span class="token function">RegisterLocalCache</span><span class="token punctuation">(</span><span class="token string">&quot;test&quot;</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span></span>
<span class="line">engine<span class="token punctuation">,</span> err <span class="token operator">:=</span> registry<span class="token punctuation">.</span><span class="token function">Validate</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>When <code>limit</code> is <code>0</code>, the cache has no size limit and will grow unbounded. When <code>limit</code> is greater than <code>0</code>, the cache uses an LRU (Least Recently Used) eviction policy -- once the limit is reached, the least recently used entry is evicted to make room for a new one.</p><h2 id="accessing-the-local-cache-data-pool" tabindex="-1"><a class="header-anchor" href="#accessing-the-local-cache-data-pool"><span>Accessing the Local Cache Data Pool</span></a></h2><p>Access the local cache through the engine:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">cache <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">LocalCache</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">)</span></span>
<span class="line">config <span class="token operator">:=</span> cache<span class="token punctuation">.</span><span class="token function">GetConfig</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">config<span class="token punctuation">.</span><span class="token function">GetCode</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment">// &quot;default&quot;</span></span>
<span class="line">config<span class="token punctuation">.</span><span class="token function">GetLimit</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// 0</span></span>
<span class="line"></span>
<span class="line">cache <span class="token operator">=</span> engine<span class="token punctuation">.</span><span class="token function">LocalCache</span><span class="token punctuation">(</span><span class="token string">&quot;test&quot;</span><span class="token punctuation">)</span></span>
<span class="line">config <span class="token operator">=</span> cache<span class="token punctuation">.</span><span class="token function">GetConfig</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">config<span class="token punctuation">.</span><span class="token function">GetCode</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment">// &quot;test&quot;</span></span>
<span class="line">config<span class="token punctuation">.</span><span class="token function">GetLimit</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// 100</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="localcache-interface" tabindex="-1"><a class="header-anchor" href="#localcache-interface"><span>LocalCache Interface</span></a></h2><p>The <code>LocalCache</code> interface provides the following public methods:</p><table><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>Get(ctx, key) (value, ok)</code></td><td>Retrieves a value by key</td></tr><tr><td><code>Set(ctx, key, value)</code></td><td>Stores a value with the given key</td></tr><tr><td><code>Remove(ctx, key)</code></td><td>Removes a value by key</td></tr><tr><td><code>Clear(ctx)</code></td><td>Removes all values from the cache</td></tr><tr><td><code>GetConfig() LocalCacheConfig</code></td><td>Returns the cache configuration</td></tr><tr><td><code>GetUsage() []LocalCacheUsage</code></td><td>Returns current cache usage statistics</td></tr></tbody></table><h2 id="retrieving-a-value" tabindex="-1"><a class="header-anchor" href="#retrieving-a-value"><span>Retrieving a Value</span></a></h2><p>Use the <code>Get()</code> method to retrieve a single value from the local cache:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">cache <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">LocalCache</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">)</span></span>
<span class="line">value<span class="token punctuation">,</span> found <span class="token operator">:=</span> cache<span class="token punctuation">.</span><span class="token function">Get</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;test-key&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> found <span class="token punctuation">{</span></span>
<span class="line">    fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Found: %v\\n&quot;</span><span class="token punctuation">,</span> value<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;Not found&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="storing-a-value" tabindex="-1"><a class="header-anchor" href="#storing-a-value"><span>Storing a Value</span></a></h2><p>Use the <code>Set()</code> method to store a value in the local cache. The value can be of any type:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">cache <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">LocalCache</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">)</span></span>
<span class="line">cache<span class="token punctuation">.</span><span class="token function">Set</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;test-key&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;my value&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">cache <span class="token operator">=</span> engine<span class="token punctuation">.</span><span class="token function">LocalCache</span><span class="token punctuation">(</span><span class="token string">&quot;test&quot;</span><span class="token punctuation">)</span></span>
<span class="line">cache<span class="token punctuation">.</span><span class="token function">Set</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;another-key&quot;</span><span class="token punctuation">,</span> <span class="token operator">&amp;</span>SomeStruct<span class="token punctuation">{</span>Field<span class="token punctuation">:</span> <span class="token string">&quot;hello&quot;</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>When using a cache with a limit, if the cache is full, the least recently used entry is automatically evicted.</p><h2 id="removing-a-value" tabindex="-1"><a class="header-anchor" href="#removing-a-value"><span>Removing a Value</span></a></h2><p>Use the <code>Remove()</code> method to remove a value from the local cache:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">cache<span class="token punctuation">.</span><span class="token function">Remove</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;key1&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="clearing-the-cache" tabindex="-1"><a class="header-anchor" href="#clearing-the-cache"><span>Clearing the Cache</span></a></h2><p>Use the <code>Clear()</code> method to remove all values from the local cache:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">cache<span class="token punctuation">.</span><span class="token function">Clear</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="cache-usage-statistics" tabindex="-1"><a class="header-anchor" href="#cache-usage-statistics"><span>Cache Usage Statistics</span></a></h2><p>Use the <code>GetUsage()</code> method to inspect the current state of the cache. It returns a slice of <code>LocalCacheUsage</code> structs:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">cache <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">LocalCache</span><span class="token punctuation">(</span><span class="token string">&quot;test&quot;</span><span class="token punctuation">)</span></span>
<span class="line">usages <span class="token operator">:=</span> cache<span class="token punctuation">.</span><span class="token function">GetUsage</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> usage <span class="token operator">:=</span> <span class="token keyword">range</span> usages <span class="token punctuation">{</span></span>
<span class="line">    fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Type: %s, Used: %d, Limit: %d, Evictions: %d\\n&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        usage<span class="token punctuation">.</span>Type<span class="token punctuation">,</span> usage<span class="token punctuation">.</span>Used<span class="token punctuation">,</span> usage<span class="token punctuation">.</span>Limit<span class="token punctuation">,</span> usage<span class="token punctuation">.</span>Evictions<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The <code>LocalCacheUsage</code> struct contains:</p><table><thead><tr><th>Field</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>Type</code></td><td><code>string</code></td><td>The type of cache partition (e.g. <code>&quot;Global&quot;</code>, <code>&quot;Entities UserEntity&quot;</code>)</td></tr><tr><td><code>Limit</code></td><td><code>uint64</code></td><td>The configured maximum number of entries (<code>0</code> means unlimited)</td></tr><tr><td><code>Used</code></td><td><code>uint64</code></td><td>The current number of entries stored</td></tr><tr><td><code>Evictions</code></td><td><code>uint64</code></td><td>The total number of entries evicted due to the LRU policy</td></tr></tbody></table><p>For a global (non-entity) local cache, <code>GetUsage()</code> returns a single entry with <code>Type</code> set to <code>&quot;Global&quot;</code>. For entity-bound caches, it returns separate entries for entities and each list reference.</p>`,30)]))}const i=n(c,[["render",o]]),u=JSON.parse('{"path":"/guide/local_cache.html","title":"Local Cache","lang":"en-US","frontmatter":{},"git":{"updatedTime":1772273114000,"contributors":[{"name":"Lukasz Lato","username":"","email":"latolukasz@gmail.com","commits":5},{"name":"lukaszjezapkowicz","username":"lukaszjezapkowicz","email":"ljezapkowicz@gamesture.com","commits":1,"url":"https://github.com/lukaszjezapkowicz"},{"name":"lukaszlato","username":"lukaszlato","email":"latolukasz@gmail.com","commits":9,"url":"https://github.com/lukaszlato"}],"changelog":[{"hash":"456e3bba4fa5c1476f9974b418e090017f6b0cc2","time":1772273114000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"New ORM"},{"hash":"2b4ccf298dcae121a76ac0374b03ee57c2d64e69","time":1761666166000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"a257bec7fda5983880990cb548ead6fdbd42b40a","time":1761657446000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"91d64256be036bf1a78ee006b85f8604baceedc4","time":1759837372000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"fluxaorm"},{"hash":"92ddda252d5fd171e1e77c1d46a26f3ab0ab2e59","time":1754686962000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"fluxaorm"},{"hash":"d8436b5413bd99b4037fecd6c95be27cef70e370","time":1753907096000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"316a31e0c87cadff2385ecc502474311a5584360","time":1703064516000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"346b7c1f17bbf34b58b9832e7a17eca6b4e45ce1","time":1699011586000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"d17272bbe68865c9decabf6b49e1eff3082611d7","time":1672663042000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"entity.Clone()"},{"hash":"b905fe3e2a0658d158ce9dff4d1bb299866a698e","time":1671799025000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"entity.Clone()"},{"hash":"3565d4203624a269e3ced947a666e4258776d437","time":1660209586000,"email":"ljezapkowicz@gamesture.com","author":"lukaszjezapkowicz","message":"typos part 2"},{"hash":"ab2ad53b6a534be4cba3768ed94da50630c75a0b","time":1629702328000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"1a84fe401aac546f204f5a30104fd0813d783458","time":1628088902000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"1eed361bbdde9d8ac709edb1366829ee34d250b4","time":1624012316000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"33dcc6580fea345bcd6968766efc9896354062da","time":1624005904000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"}]},"filePathRelative":"guide/local_cache.md"}');export{i as comp,u as data};
